external_knowledge:
- 'initial event' refers to the event with event_id = 0;
- 'combined fencing prowess' corresponds to the sum of fencing ratings;
- 'actually showed up' means the participation status is 'attended'.

sql:
SELECT event_id, event_code, event_type, division_id, primary_club_id, event_date, location, description, event_format, event_status, max_participants, registration_deadline 
FROM events 
WHERE primary_club_id = 5;

SELECT AVG(event_count) AS avg_event_count
  FROM (
    SELECT division_id, COUNT(*) AS event_count
    FROM events
    GROUP BY division_id
  ) AS event_counts;
